public inline fun <C> mapLeft(fa: (A) -> C): Ior<C, B> {
  contract {
    callsInPlace(fa, InvocationKind.AT_MOST_ONCE)
    (this@Ior !is Right) holdsIn fa
  }
  return when (this) {
    is Left -> Left(fa(value))
    is Right -> this
    is Both -> Both(fa(leftValue), rightValue)
  }
}

@OptIn(ExperimentalExtendedContracts::class)
@RaiseDSL
public inline fun <Error> Raise<Error>.ensure(condition: Boolean, raise: () -> Error) {
  contract {
    callsInPlace(raise, AT_MOST_ONCE)
    returns() implies condition
    !condition holdsIn raise
  }
  return if (condition) Unit else raise(raise())
}

inline fun <reified T> _createDefinition(
