inline fun <reified T> single(
    qualifier: Qualifier? = null,
    createdAtStart: Boolean = false,
    noinline definition: Definition<T>,
): KoinDefinition<T> {
    val factory = _singleInstanceFactory(qualifier, definition)
    indexPrimaryType(factory)
    if (createdAtStart || this._createdAtStart) {
        prepareForCreationAtStart(factory)
    }
    return KoinDefinition(this, factory)
}

public fun <T> CoroutineScope.async(
    context: CoroutineContext = EmptyCoroutineContext,
    start: CoroutineStart = CoroutineStart.DEFAULT,
    block: suspend CoroutineScope.() -> T
): Deferred<T> {
    val newContext = newCoroutineContext(context)
    val coroutine = if (start.isLazy)
        LazyDeferredCoroutine(newContext, block) else
        DeferredCoroutine<T>(newContext, active = true)
    coroutine.start(start, coroutine, block)
    return coroutine
}

public suspend inline fun <T> Mutex.withLock(owner: Any? = null, action: () -> T): T {
    contract {
        callsInPlace(action, InvocationKind.EXACTLY_ONCE)
    }
    lock(owner)
    return try {
        action()
    } finally {
        unlock(owner)
    }
}

public suspend fun <T> withTimeout(timeMillis: Long, block: suspend CoroutineScope.() -> T): T {
    contract {
        callsInPlace(block, InvocationKind.EXACTLY_ONCE)
    }
    if (timeMillis <= 0L) throw TimeoutCancellationException("Timed out immediately")
    return suspendCoroutineUninterceptedOrReturn { uCont ->
        setupTimeout(TimeoutCoroutine(timeMillis, uCont), block)
    }
}

private class ProducerCoroutine<E>(
    parentContext: CoroutineContext, channel: Channel<E>
) : ChannelCoroutine<E>(parentContext, channel, true, active = true), ProducerScope<E> {
    override val isActive: Boolean
        get() = super.isActive

    override fun onCompleted(value: Unit) {
        _channel.close()
    }

    override fun onCancelled(cause: Throwable, handled: Boolean) {
        val processed = _channel.close(cause)
        if (!processed && !handled) handleCoroutineException(context, cause)
    }
}

public suspend fun <R> supervisorScope(block: suspend CoroutineScope.() -> R): R {
    contract {
        callsInPlace(block, InvocationKind.EXACTLY_ONCE)
    }
    return suspendCoroutineUninterceptedOrReturn { uCont ->
        val coroutine = SupervisorCoroutine(uCont.context, uCont)
        coroutine.startUndispatchedOrReturn(coroutine, block)
    }
}

internal fun <T : Any> BooleanExpression<T>.evaluate(block: (T) -> Boolean): Boolean {
  return when (this) {
    BooleanExpression.True -> true
    BooleanExpression.False -> false
    is BooleanExpression.Not -> !operand.evaluate(block)
    is BooleanExpression.Or -> operands.any { it.evaluate(block) }
    is BooleanExpression.And -> operands.all { it.evaluate(block) }
    is BooleanExpression.Element -> block(value)
  }
}

fun map(data: Any, options: Options): Any {
    var mappedData = data
    mappers.forEachIndices { (mapper, type) ->
        if (type.isInstance(mappedData)) {
            (mapper as Mapper<Any, *>).map(mappedData, options)?.let { mappedData = it }
        }
    }
    return mappedData
}

fun getCacheValue(
    request: ImageRequest,
    cacheKey: MemoryCache.Key,
    size: Size,
    scale: Scale,
): MemoryCache.Value? {
    if (!request.memoryCachePolicy.readEnabled) return null
    val cacheValue = imageLoader.memoryCache?.get(cacheKey)
    return cacheValue?.takeIf { isCacheValueValid(request, cacheKey, it, size, scale) }
}

private fun <T> resolve(
    clazz: KClass<*>,
    qualifier: Qualifier?,
    parameters: ParametersHolder? = null
): T {
    if (!_koin.logger.isAt(Level.DEBUG)) {
        return resolveInstance(qualifier, clazz, parameters)
    }

    logInstanceRequest(clazz, qualifier)
    val result = measureTimedValue { resolveInstance<T>(qualifier, clazz, parameters) }
    logInstanceDuration(clazz, result.duration)

    return result.value
}

internal fun TimeoutCancellationException(
    time: Long,
    delay: Delay,
    coroutine: Job,
    coroutineName: String?
): TimeoutCancellationException {
    val baseMessage = (delay as? DelayWithTimeoutDiagnostics)?.timeoutMessage(time.milliseconds)
        ?: "Timed out waiting for $time ms"
    val message = if (coroutineName != null) {
        "Coroutine \"$coroutineName\" ${baseMessage.replaceFirstChar { it.lowercaseChar() }}"
    } else {
        baseMessage
    }
    return TimeoutCancellationException(message, coroutine)
}

public fun insertPhaseBefore(reference: PipelinePhase, phase: PipelinePhase) {
    if (hasPhase(phase)) return

    val index = findPhaseIndex(reference)
    if (index == -1) {
        throw InvalidPhaseException("Phase $reference was not registered for this pipeline")
    }

    phasesRaw.add(index, PhaseContent<TSubject, TContext>(phase, PipelinePhaseRelation.Before(reference)))
}

