@JvmName("-toJson")
@JvmOverloads
fun <T> Adapter<T>.toJsonString(
    value: T,
    customScalarAdapters: CustomScalarAdapters = CustomScalarAdapters.Empty,
    indent: String? = null,
): String = buildJsonString(indent) {
  this@toJsonString.toJson(this, customScalarAdapters, value)
}

override fun fromJson(reader: JsonReader, customScalarAdapters: CustomScalarAdapters): T {
  if (reader.peek() == JsonReader.Token.NULL) {
    val error = customScalarAdapters.firstErrorStartingWith(reader.getPath())
    if (error != null) {
      reader.skipValue()
      throw ApolloGraphQLException(error)
    }
  }

  return wrappedAdapter.fromJson(reader, customScalarAdapters)
}

override fun fromJson(reader: JsonReader, customScalarAdapters: CustomScalarAdapters): FieldResult<T> {
  return try {
    FieldResult.Success(wrappedAdapter.fromJson(reader, customScalarAdapters))
  } catch (e: ApolloException) {
    FieldResult.Failure(e)
  }
}

fun BooleanExpression<BTerm>.evaluate(
    variables: Set<String>?,
    typename: String?,
    deferredFragmentIdentifiers: Set<DeferredFragmentIdentifier>?,
    path: List<Any>?,
): Boolean {
  // Remove "data" from the path
  val croppedPath = path?.drop(1)
  return evaluate {
    when (it) {
      is BVariable -> !(variables?.contains(it.name) ?: false)
      is BLabel -> shouldParseFragment(deferredFragmentIdentifiers, croppedPath!!, it.label)
      is BPossibleTypes -> it.possibleTypes.contains(typename)
    }
  }
}

@ApolloExperimental
  fun argumentValues(variables: Executable.Variables, filter: (CompiledArgument) -> Boolean = { true }): Map<String, ApolloJsonElement> {
    val arguments = arguments.filter(filter).filter { it.value is Optional.Present<*> }
    if (arguments.isEmpty()) {
      return emptyMap()
    }
    val map = arguments.associate { it.definition.name to it.value.getOrThrow() }

    @Suppress("UNCHECKED_CAST")
    return resolveVariables(map, variables) as Map<String, ApolloJsonElement>
  }
